#!/usr/bin/env python3
"""
Vendor Appointments Update — Backend + Frontend
Run from ~/seller-portal:
    python3 update_vendors.py
"""
import base64, os, sys

if not os.path.exists("frontend/src/pages") or not os.path.exists("backend/main.py"):
    print("Error: Run this from your ~/seller-portal directory")
    sys.exit(1)

files = {}
files["backend/main.py"] = ""
files["frontend/src/pages/AdminPropertyDetail.jsx"] = ""
files["frontend/src/pages/ClientDashboard.jsx"] = ""
files["frontend/src/utils/api.js"] = ""

for path, data in files.items():
    content = base64.b64decode(data)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(content)
    print(f"  Updated: {path} ({len(content):,} bytes)")

print()
print("All files updated! Now run:")
print("  git add -A && git commit -m \"Vendor appointments: backend + admin + client views\" && git push")
print()
print("Railway will auto-deploy from the push.")
